771	async function consultClusterForCaller(
772	  runtime: RouterRuntime,
773	  consultService: ConsultService,
774	  input: {
775	    projectId: string;
776	    clusterId: string;
777	    question: string;
778	    toolProfile?: "bare" | "focused" | "agent" | null;
779	  }
780	): Promise<ClusterConsultResult | ConsultResult> {
781	  const availability = await runtime.getProfileAvailability();
782	  const result = await consultCluster(runtime.db, runtime.cwd, runtime.claude, availability, input);
783	  if (!("error" in result)) {
784	    return result;
785	  }
786	  if (shouldReturnClusterErrorToCaller(result)) {
787	    return result;
788	  }
789	  if (result.error.code !== ERROR_CODES.CLUSTER_FACTSHEET_STALE || !runtime.config.cluster.autoRefresh) {
790	    return fallbackToClaudeConsult(runtime, consultService, input, result);
791	  }
792	
793	  return runtime.locks.withLock(`cluster-evidence-revalidation:${input.projectId}:${input.clusterId}`, async () => {
794	    const afterWaitAvailability = await runtime.getProfileAvailability();
795	    const afterWaitResult = await consultCluster(runtime.db, runtime.cwd, runtime.claude, afterWaitAvailability, input);
796	    if (!("error" in afterWaitResult)) {
797	      return afterWaitResult;
798	    }
799	    if (shouldReturnClusterErrorToCaller(afterWaitResult)) {
800	      return afterWaitResult;
801	    }
802	    if (afterWaitResult.error.code !== ERROR_CODES.CLUSTER_FACTSHEET_STALE) {
803	      return fallbackToClaudeConsult(runtime, consultService, input, afterWaitResult);
804	    }
805	
806	    const revalidation = revalidateClusterEvidence(runtime.db, runtime.cwd, {
807	      projectId: input.projectId,
808	      clusterId: input.clusterId,
809	      minRetainedRatio: runtime.config.cluster.autoRefreshMinRetainedRatio
810	    });
811	    if ("error" in revalidation) {
812	      return fallbackToClaudeConsult(runtime, consultService, input, revalidation);
813	    }
814	
815	    const refreshedAvailability = await runtime.getProfileAvailability();
816	    return consultCluster(runtime.db, runtime.cwd, runtime.claude, refreshedAvailability, input);
817	  });
818	}
