820	async function fallbackToClaudeConsult(
821	  runtime: RouterRuntime,
822	  consultService: ConsultService,
823	  input: {
824	    projectId: string;
825	    clusterId: string;
826	    question: string;
827	  },
828	  revalidationError: Exclude<ClusterConsultResult, { answer: string }>
829	): Promise<ConsultResult> {
830	  runtime.db.markClusterNeedsPrepare(input.clusterId);
831	  const startedAt = runtime.clock.nowMillis();
832	  const result = await consultService.consult({
833	    projectId: input.projectId,
834	    topicHint: `cluster fallback ${input.clusterId}`,
835	    trigger: "cluster_consult_fallback",
836	    task: "Answer the caller's question after cluster evidence revalidation failed.",
837	    relevantCode: [
838	      `Cluster '${input.clusterId}' factsheet evidence failed strict revalidation.`,
839	      "Use normal project understanding/discovery as needed. Do not rely on the stale cluster factsheet."
840	    ].join("\n"),
841	    question: input.question
