927	function buildMonitorRecommendations(input: {
928	  degradedMode: boolean;
929	  degradedReason?: string;
930	  shadowEnabled: boolean;
931	  shadowEval: ShadowEvalHealth;
932	  staleClusters: StaleClusterView[];
933	  sessionErrors: EventCount[];
934	  clusterAttentionByCluster: ClusterEventCount[];
935	  comparisonStats: ConsultComparisonMonitorStats[];
936	}): Array<{ priority: "high" | "medium" | "low"; area: string; cluster_id?: string | null; action: string; reason: string }> {
937	  const recommendations: Array<{
938	    priority: "high" | "medium" | "low";
939	    area: string;
940	    cluster_id?: string | null;
941	    action: string;
942	    reason: string;
