949	      action: "Fix Claude CLI compatibility/auth and run claude_router_reset.",
950	      reason: input.degradedReason ?? "Router is in degraded mode."
951	    });
952	  }
953	
954	  if (!input.shadowEnabled) {
955	    recommendations.push({
956	      priority: "medium",
