970	      reason: `Shadow eval has ${stalledShadow} unjudged comparison(s).`
971	    });
972	  }
973	  if (failedShadow > 0) {
974	    recommendations.push({
975	      priority: "high",
976	      area: "monitoring",
977	      action: "Fix shadow direct baseline failures before trusting comparison coverage.",
978	      reason: `Shadow eval has ${failedShadow} failed comparison(s).`
979	    });
980	  }
981	
982	  for (const cluster of input.staleClusters) {
983	    recommendations.push({
984	      priority: "high",
985	      area: "cache",
986	      cluster_id: cluster.id,
987	      action: "Run cluster_prepare or expand/rebuild this factsheet.",
