989	    });
990	  }
991	
992	  for (const event of input.clusterAttentionByCluster) {
993	    if (event.event_type === "cluster_fallback_failed") {
994	      recommendations.push({
995	        priority: "high",
996	        area: "fallback",
997	        cluster_id: event.cluster_id,
998	        action: "Investigate Claude availability and fallback path immediately.",
999	        reason: `Fallback failed ${event.count} time(s) in the recent window.`
1000	      });
1001	    } else if (event.event_type === "cluster_fallback_to_claude_consult") {
1002	      recommendations.push({
1003	        priority: "medium",
1004	        area: "cache",
1005	        cluster_id: event.cluster_id,
1006	        action: "Re-prepare or broaden this cluster if fallback is recurring.",
1007	        reason: `Router fell back to claude_consult ${event.count} time(s), meaning cache could not serve those calls.`
1008	      });
1009	    } else if (event.event_type === "evidence_revalidation_failed") {
1010	      recommendations.push({
1011	        priority: "medium",
1012	        area: "cache",
1013	        cluster_id: event.cluster_id,
1014	        action: "Refresh factsheet evidence; selectors or snippets changed.",
1015	        reason: `Strict evidence revalidation failed ${event.count} time(s).`
1016	      });
1017	    } else if (event.event_type === "tool_profile_downgraded" || event.event_type === "bare_probe_failed") {
