1060	function buildMonitorNextDirections(
1061	  comparisonStats: ConsultComparisonMonitorStats[],
1062	  clusterAttentionByCluster: ClusterEventCount[],
1063	  staleClusters: StaleClusterView[],
1064	  shadowEval: ShadowEvalHealth
1065	): string[] {
1066	  const directions: string[] = [];
1067	  const hasQualityData = comparisonStats.some((stats) => stats.judged > 0);
1068	  const strongClusters = comparisonStats.filter((stats) => (stats.judged ?? 0) >= 3 && (stats.gap ?? 1) <= 0);
1069	  const weakClusters = comparisonStats.filter((stats) => (stats.direct_wins ?? 0) > 0 || (stats.not_in_context ?? 0) > 0);
1070	  const fallbackClusters = new Set(
1071	    clusterAttentionByCluster
1072	      .filter((event) => event.event_type === "cluster_fallback_to_claude_consult" || event.event_type === "evidence_revalidation_failed")
1073	      .map((event) => event.cluster_id)
1074	  );
1075	
1076	  if (!hasQualityData) {
1077	    directions.push("Collect more shadow comparisons before deciding on auto-routing or factsheet expansion.");
1078	  }
1079	  if (weakClusters.length > 0) {
1080	    directions.push("Prioritize factsheet expansion or distillation for clusters where direct wins or NOT IN CONTEXT appears.");
1081	  }
1082	  if (strongClusters.length > 0 && fallbackClusters.size === 0 && staleClusters.length === 0) {
1083	    directions.push("Clusters with stable quality and no fallback are candidates for future automatic cluster routing.");
1084	  }
1085	  if (fallbackClusters.size > 0 || staleClusters.length > 0) {
1086	    directions.push("Re-prepare decayed clusters before using their data to judge routing quality.");
1087	  }
1088	  if (shadowEval.failed_auth + shadowEval.failed_timeout + shadowEval.failed_other > 0 || shadowEval.pending + shadowEval.ok_unjudged > 0) {
1089	    directions.push("Stabilize the shadow pipeline before trusting long-term trend reports.");
1090	  }
1091	  if (comparisonStats.some((stats) => (stats.judged ?? 0) >= 10 && (stats.gap ?? 1) <= 0 && (stats.not_in_context ?? 0) === 0)) {
1092	    directions.push("Fork baselines are still low priority unless monitor data shows latency/cost, not quality, is the bottleneck.");
1093	  }
1094	
1095	  return directions;
1096	}
